import base64, os

files = {
    'backend/config/domain-priors/exact.json': '',
}

base = r'C:\Users\Lenovo\OneDrive\Desktop\serper-app'

for rel, b64 in files.items():
    path = os.path.join(base, rel.replace('/', os.sep))
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'wb') as f:
        f.write(base64.b64decode(b64))
    print('Written:', path)

print()
print('Now run:')
print('  git add backend/config/domain-priors/exact.json')
print('  git commit -m "Add domain priors: golfergeeks, rickshiels, news10, wreg, dailymotion, acast"')
print('  git push origin main')
print()
print('Then on server:')
print('  cd /var/www/serper-app && git pull origin main && pm2 restart serper-backend')
